val lifecycleOwner = LocalLifecycleOwner.current
DisposableEffect(lifecycleOwner) {
    val observer = LifecycleEventObserver { _, event -> /* handle */ }
    lifecycleOwner.lifecycle.addObserver(observer)
    onDispose { lifecycleOwner.lifecycle.removeObserver(observer) }
}

@Composable
fun Parent() {
    var text by remember { mutableStateOf("") }
    Child(text = text, onTextChange = { text = it })
}

@Composable
fun Child(text: String, onTextChange: (String) -> Unit) {
    TextField(value = text, onValueChange = onTextChange)
}

val scope = rememberCoroutineScope()
Button(onClick = { 
    scope.launch { fetchData() } 
})

@Composable
fun UserScreen(userId: String) {
    LaunchedEffect(userId) {
        val userData = fetchUserData(userId) // suspend function
        // Update UI
    }
}

@Composable
fun FetchButton() {
    val scope = rememberCoroutineScope()
    Button(onClick = {
        scope.launch {
            fetchData() // suspend function
        }
    }) {
        Text("Fetch Data")
    }
}
